sql:
SELECT COUNT(*) 
FROM products 
WHERE gain > 5;

SELECT type_name
FROM product_types
WHERE type_id = 1;

SELECT SUM(quantity) AS product_count
FROM inventory
WHERE warehouse_id = (SELECT warehouse_id FROM warehouses WHERE warehouse_name = 'Warehouse 1');

external_knowledge:
- 'main storage area' refers to 'Warehouse A';
- 'best-stocked' means the products with the highest quantity in stock;
- 'top 10 most abundant products' refers to the products ranked top 10 by quantity.

sql:
SELECT product_type, COUNT(*) AS product_count
FROM products
GROUP BY product_type;

SELECT product_id, part_number, product_type, gain
FROM products
WHERE gain = (SELECT MAX(gain) FROM products);

external_knowledge:
- 'top performers' here refers to the products with the highest gain within their category; 
- 'best five in each category' indicates the top five products based on gain for each product type;
- 'gain' is a measure of the product's efficiency, typically expressed in dBi.

sql:
SELECT product_id
FROM products
ORDER BY product_id;

SELECT part_number
FROM products
WHERE product_type = (SELECT type_id FROM product_types WHERE type_name = 'Antenna');

SELECT COUNT(product_id) 
FROM inventory 
WHERE quantity > 10;

SELECT COUNT(*) AS low_stock_products
FROM inventory
WHERE quantity < reorder_level;
